namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords =
    [
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "as", "it",
        "that", "this", "from", "be", "been", "being", "have", "has", "had",
        "do", "does", "did", "will", "would", "could", "should", "may",
        "might", "not", "so", "if", "then", "than", "too", "very", "can",
        "just", "about", "into", "over", "after", "before", "between",
        "each", "which", "their", "there", "these", "those", "its", "also"
    ];

    public SummarizeResult Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResult
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences, preserving original order
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));

        return new SummarizeResult
        {
            Summary = summary,
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topIndices.Count
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                var lower = word.ToLowerInvariant();
                if (StopWords.Contains(lower) || lower.Length < 2)
                    continue;

                frequencies.TryGetValue(lower, out var count);
                frequencies[lower] = count + 1;
            }
        }

        // Normalize by max frequency
        if (frequencies.Count > 0)
        {
            var maxFreq = frequencies.Values.Max();
            foreach (var key in frequencies.Keys.ToList())
                frequencies[key] /= maxFreq;
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            double score = 0;
            int counted = 0;

            foreach (var word in words)
            {
                if (wordFrequencies.TryGetValue(word.ToLowerInvariant(), out var freq))
                {
                    score += freq;
                    counted++;
                }
            }

            // Average score to avoid bias toward long sentences
            scores.Add(counted > 0 ? score / counted : 0);
        }

        return scores;
    }

    private static string[] Tokenize(string text) =>
        WordToken().Matches(text).Select(m => m.Value).ToArray();

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordToken();
}

public class SummarizeResult
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest(new { error = "Text is required and cannot be empty." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var result = _service.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = result.Summary,
            OriginalSentenceCount = result.OriginalSentenceCount,
            SummarySentenceCount = result.SummarySentenceCount
        });
    }
}

